export function getIconForLanguageExtension(language: string) {
  switch (language) {
    case "json":
      return <JsonIcon />
    case "css":
      return <CssIcon />
    case "js":
      return <JsIcon />
    case "ts":
    case "typescript":
      return <TsIcon />
    case "jsx":
    case "tsx":
      return <ReactIcon />
    default:
      return <FileIcon />
  }
}

export function getIconForPackageManager(manager: string) {
  switch (manager) {
    case "pnpm":
      return <PnpmIcon />
    case "yarn":
      return <YarnIcon />
    case "npm":
      return <NpmIcon />
    case "bun":
      return <BunIcon />
    default:
      return <TerminalSquareIcon />
  }
}
